#define THREADS 256

inline int dwt53_predict_int(const int even_prev, const int odd, const int even_next)
{
    return odd - ((even_prev + even_next) / 2);
}

inline int dwt53_update_int(const int detail_prev, const int even, const int detail_next)
{
    return even + ((detail_prev + detail_next + 2) / 4);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    const int x = (int)get_global_id(0);

    if (x < pixels) {
        const int offset = x * 3;
        d_r[x] = ((int)d_src[offset + 0]) - 128;
        d_g[x] = ((int)d_src[offset + 1]) - 128;
        d_b[x] = ((int)d_src[offset + 2]) - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    const int x = (int)get_global_id(0);

    if (x < pixels) {
        d_c[x] = ((int)d_src[x]) - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) {
        return;
    }

    const int lowW = (sizeX + 1) >> 1;
    const int highW = sizeX >> 1;
    const int lowH = (sizeY + 1) >> 1;
    const int highH = sizeY >> 1;

    const int llBase = 0;
    const int hlBase = lowW * lowH;
    const int lhBase = hlBase + highW * lowH;
    const int hhBase = lhBase + lowW * highH;


    for (int y = 0; y < sizeY; ++y) {
        const int inBase = y * sizeX;
        const int outBase = y * sizeX;

        if (highW == 0) {
            output[outBase] = input[inBase];
            continue;
        }

        for (int i = 0; i < highW; ++i) {
            const int even0 = input[inBase + (i << 1)];
            const int odd   = input[inBase + (i << 1) + 1];
            const int even1 = (((i << 1) + 2) < sizeX)
                            ? input[inBase + (i << 1) + 2]
                            : input[inBase + (i << 1)];
            output[outBase + lowW + i] = dwt53_predict_int(even0, odd, even1);
        }

        for (int i = 0; i < lowW; ++i) {
            const int even = input[inBase + (i << 1)];
            const int prevD = (i == 0)
                            ? output[outBase + lowW]
                            : output[outBase + lowW + i - 1];
            const int nextD = (i < highW)
                            ? output[outBase + lowW + i]
                            : output[outBase + lowW + highW - 1];
            output[outBase + i] = dwt53_update_int(prevD, even, nextD);
        }
    }


    for (int x = 0; x < sizeX; ++x) {
        const int isLowBand = (x < lowW);
        const int colOut = isLowBand ? x : (x - lowW);
        const int bandW = isLowBand ? lowW : highW;
        const int lowBase = isLowBand ? llBase : hlBase;
        const int highBase = isLowBand ? lhBase : hhBase;

        if (highH == 0) {
            input[lowBase + colOut] = output[x];
            continue;
        }

        for (int i = 0; i < highH; ++i) {
            const int even0 = output[(i << 1) * sizeX + x];
            const int odd   = output[((i << 1) + 1) * sizeX + x];
            const int even1 = ((((i << 1) + 2) < sizeY))
                            ? output[((i << 1) + 2) * sizeX + x]
                            : output[(i << 1) * sizeX + x];
            input[highBase + i * bandW + colOut] = dwt53_predict_int(even0, odd, even1);
        }

        for (int i = 0; i < lowH; ++i) {
            const int even = output[(i << 1) * sizeX + x];
            const int prevD = (i == 0)
                            ? input[highBase + colOut]
                            : input[highBase + (i - 1) * bandW + colOut];
            const int nextD = (i < highH)
                            ? input[highBase + i * bandW + colOut]
                            : input[highBase + (highH - 1) * bandW + colOut];
            input[lowBase + i * bandW + colOut] = dwt53_update_int(prevD, even, nextD);
        }
    }


    for (int i = 0; i < sizeX * sizeY; ++i) {
        output[i] = input[i];
    }
}
